create table dirkspzm32.lvs_lgr_ort (
    sid                         varchar2(2 char) default '01' not null enable,
    firma_nr                    number(2, 0) default 1 not null enable,
    lgr_ort                     number(5, 0) not null enable,
    lgr_ort_text                varchar2(30 char),
    lgr_platz_cfg               varchar2(30 char),
    lgr_dim_g_text              varchar2(20 char) default 'Gang',
    lgr_dim_r_text              varchar2(20 char) default 'Reiihe',
    lgr_dim_p_text              varchar2(20 char) default 'Platz',
    lgr_dim_e_text              varchar2(20 char) default 'Ebene',
    lgr_dim_t_text              varchar2(20 char) default 'Tiefe',
    stapler_ls_id               number(*, 0),
    adress_id                   number(*, 0),
    host_lgr_ort                varchar2(20 char),
    lgr_lte_namen               varchar2(300 char),
    lgr_ort_modul               varchar2(4 char) default 'LVS' not null enable,
    lgr_typ                     varchar2(12 char),
    lgr_einl_opti               varchar2(1 char) default 'F' not null enable,
    akt_inventur_id             number(*, 0),
    letzte_inventur_id          number(*, 0),
    letzte_inventur_datum       date,
    letzte_inventur_login_id    number(*, 0),
    lgr_platz_eti_pfeil_richt   varchar2(1 char),
    komm_direkt_moegl           varchar2(1 char) default 'T',
    komm_ausweich_lgr_platz     varchar2(30 char),
    komm_picken_moegl           varchar2(1 char) default 'T',
    komm_neu_lte_lgr_platz      varchar2(30 char),
    lgr_ort_block_trans_erlaubt varchar2(1 char) default 'F' not null enable,
    lgr_dim_r_g_u_gegenueber    varchar2(1 char) default 'F',
    strat_regal_hoehe_fw        number(*, 3) default 1 not null enable,
    strat_regal_hoehe_rw        number(*, 3) default 1 not null enable,
    strat_regal_hoehe_hw        number(*, 3) default 1 not null enable,
    strat_regal_hoehe_mp        number(*, 3) default 1 not null enable,
    strat_platz_res_string      number(*, 5) default 1 not null enable,
    strat_platz_leer            number(*, 5) default 1.1 not null enable,
    strat_platz_misch_kanal     number(*, 5) default 1.3 not null enable,
    strat_platz_falsch          number(*, 5) default 99 not null enable,
    strat_platz_factor_max      number(*, 5) default 999999999999999999999999 not null enable,
    strat_abc                   number(*, 5) default 1,
    strat_art_res               number(*, 5) default 20,
    strat_ort_abstand_faktor    number(*, 5) default - 1,
    strat_abstand_faktor        number(*, 5) default - 1,
    strat_platz_r_faktor        number(*, 5) default 0,
    strat_gewicht_relevanz      number(*, 5),
    strat_hoehe_relevanz        number(*, 5),
    strat_breite_relevanz       number(*, 5),
    strat_tiefe_relevanz        number(*, 5),
    strat_fuellgrad_relevanz    number(*, 5),
    strat_platz_ausl_dispo      number(*, 5) default 100 not null enable,
    strat_order_reservierung    number(*, 5) default 50 not null enable,
    strat_lgr_platz_verfueg     number(*, 5) default 1 not null enable,
    strat_lgr_platz_akt_lte     number(*, 5) default 1 not null enable,
    verl_vorb_lgr_orte          varchar2(100 char),
    strat_platz_misch_pal       number(*, 5) default 1.4,
    lgr_ort_vol_hoehe           number(*, 3),
    lgr_ort_vol_breite          number(*, 3),
    lgr_ort_vol_tiefe           number(*, 3),
    lgr_ort_raster_x            number(*, 3),
    lgr_ort_raster_y            number(*, 3),
    lgr_platz_rand_abstand_x    number(*, 5),
    lgr_platz_rand_abstand_y    number(*, 5),
    default_hoehe               number(*, 3),
    default_breite              number(*, 3),
    default_tiefe               number(*, 3),
    default_max_lte             number(*, 5),
    default_abc                 number(*, 5),
    default_wert_klasse         number(*, 5),
    default_gefahren_klasse     number(*, 5),
    default_lte_namen_cfg       varchar2(200 char),
    default_lgr_temp            number(*, 5) default 0,
    default_waren_typen_cfg     varchar2(30 char) default 'FW;',
    default_flaechen_stellplatz varchar2(1 char) default 'F',
    lgr_min_hoehe               number(*, 3),
    lgr_min_breite              number(*, 3),
    lgr_min_tiefe               number(*, 3),
    lgr_max_hoehe               number(*, 3),
    lgr_max_breite              number(*, 3),
    lgr_max_tiefe               number(*, 3),
    lgr_ort_max_kg_proz         number(*, 6) default 100 not null enable,
    lgr_ort_fuehrend_system     varchar2(30 char) default 'ISI'
);

alter table dirkspzm32.lvs_lgr_ort
    add constraint check_lgr_ort_reg_hoehe_fw
        check ( strat_regal_hoehe_fw in ( - strat_ort_abstand_faktor, 0, strat_ort_abstand_faktor ) ) enable;

alter table dirkspzm32.lvs_lgr_ort
    add constraint check_lgr_ort_typ
        check ( lgr_typ in ( 'SAT1', 'SAT_EPL1', 'SAT_EPL2', 'EPL1', 'KANAL1',
                             'KANBKL1', 'BKL1', 'REG_FACH1', 'SEG1', 'SEG_DUEDO1',
                             'DURCHL1', 'PP_EPL1', 'STAP_FLAE1', 'STAP_FLAE2' ) ) enable;

alter table dirkspzm32.lvs_lgr_ort
    add constraint pk_lgr_ort primary key ( lgr_ort )
        using index enable;


